def norm(s): 
    return normalize_arabic(s)

def token_set(s):
    return set(norm(s).split())

def token_f1(a, b):
    ta, tb = token_set(a), token_set(b)
    if not ta or not tb:
        return 0.0
    inter = len(ta & tb)
    prec = inter / len(ta)
    rec = inter / len(tb)
    if prec + rec == 0:
        return 0.0
    return 2 * prec * rec / (prec + rec)

def lcs_length(a, b):
    # approximate LCS via SequenceMatcher?
    # But SequenceMatcher ratio approximates LCS*2/(len(a)+len(b)).
    # We'll compute normalized ratio using difflib
    a_n = norm(a)
    b_n = norm(b)
    return difflib.SequenceMatcher(None, a_n, b_n).ratio()

def composite_score(a, b):
    return 0.5 * token_f1(a,b) + 0.5 * lcs_length(a,b)

